 depth // depth \u4e3a 0 \u5230 x \u7684\u8ddd\u79bb\n        size[x] = 1\n        for _, y := range g[x] { // \u904d\u5386 x \u7684\u90bb\u5c45 y\n            if y != fa { // \u907f\u514d\u8bbf\u95ee\u7236\u8282\u70b9\n                dfs(y, x, depth+1) // x \u662f y \u7684\u7236\u8282\u70b9\n                size[x] += size[y] // \u7d2f\u52a0 x \u7684\u513f\u5b50 y \u7684\u5b50\u6811\u5927\u5c0f\n            }\n        }\n    }\n    dfs(0, -1, 0) // 0 \u6ca1\u6709\u7236\u8282\u70b9\n\n    var reroot func(int, int)\n    reroot = func(x, fa int) {\n        for _, y := range g[x] { // \u904d\u5386 x \u7684\u90bb\u5c45 y\n            if y != fa { // \u907f\u514d\u8bbf\u95ee\u7236\u8282\u70b9\n                ans[y] = ans[x] + n - 2*size[y]\n                reroot(y, x) // x \u662f y \u7684\u7236\u8282\u70b9\n            }\n        }\n    }\n    reroot(0, -1) // 0 \u6ca1\u6709\u7236\u8282\u70b9\n    return ans\n}\n")),(0,a.kt)("p",null,(0,a.kt)("a",{parentName:"p",href:"https://leetcode.cn/problems/minimum-height-trees/description/"},"310. \u6700\u5c0f\u9ad8\u5ea6\u6811")),(0,a.kt)("pre",null,(0,a.kt)("code",{parentName:"pre",className:"language-go",metastring:"showLineNumbers",showLineNumbers:!0},"func findMinHeightTrees(n int, edges [][]int) []int {\n    g := make([][]int, n)\n    for _, e := range edges {\n        x, y := e[0], e[1]\n        g[x] = append(g[x], y)\n        g[y] = append(g[y], x)\n    }\n    d1 := make([]int, n)\n    d2 := make([]int, n)\n    up := make([]int, n)\n    p := make([]int, n)\n    for i := range p {\n        p[i] = -1\n    }\n    var dfs1 func(cur, fa int) int\n    dfs1 = func(cur, fa int) int {\n        for _, ne := range g[cur] {\n            if ne == fa {\n                continue\n            }\n            h := dfs1(ne, cur) + 1\n            if h > d1[cur] {\n                d2[cur] = d1[cur]\n                d1[cur] = h\n                p[cur] = ne\n            } else if h > d2[cur] {\n                d2[cur] = h\n            }\n        }\n        return d1[cur]\n    }\n    var dfs2 func(cur, fa int)\n    dfs2 = func(cur, fa int) {\n        for _, ne := range g[cur] {\n            if ne == fa {\n                continue\n            }\n            if p[cur] != ne {\n                up[ne] = max(up[ne], d1[cur]+1)\n            } else {\n                up[ne] = max(up[ne], d2[cur]+1)\n            }\n            up[ne] = max(up[ne], up[cur]+1)\n            dfs2(ne, cur)\n        }\n    }\n\n    dfs1(0, -1)\n    dfs2(0, -1)\n\n    mi := math.MaxInt\n    ans := []int{}\n    for i := 0; i < n; i++ {\n        if h := max(d1[i], up[i]); h < mi {\n            mi = h\n            ans = nil\n            ans = append(ans, i)\n        } else if h == mi {\n            ans = append(ans, i)\n        }\n    }\n    return ans\n}\n\nfunc max(a, b int) int {\n    if a > b {\n        return a\n    }\n    return b\n}\n")))}f.isMDXComponent=!0}}]);